%[text] # 사랑의 삼각관계
%[text] 
M = imread('lovetriangle.jpg'); %사진 파일(.jpg) 읽기
figure(1),  imshow(M); %사진 파일을 figure(1)이라는 이름으로 열어라 %[output:71b6e8a8]
figure(2), imshow(M(5:88, 215:335));%사진 파일 M을 행 5부터 88, 열 215부터 335가 겹치는 부분을 figure(2)라는 이름으로 열어라 %[output:764f654f]
S = M; %사진 파일 M을 S라는 이름으로 추가 -> 테두리 사진을 위해서
S(1:5, :) = 0; % 좌측 테두리 (행 1부터 5, 열 전체)
S(end-5:end, :) = 0; %우측 테두리 (행 끝-5부터 끝, 열 전체)
S(:, 1:5) = 0; %위측 테두리 (행 전체, 열 1부터 5)
S(:, end-5:end) = 0;  %아래측 테두리 (행 전체, 열 끝-5부터 끝)
figure(3), imshow(S); %S파일을 figure(3)이라는 이름으로 보여줘 %[output:906e9956]
%%
%[text] # 행렬을 이용한 이미지 편집
M = imread("lovetriangle.jpg");
figure(4), imshow(fliplr(M)); % 좌우 반전 %[output:2e47ce4d]
figure(5), imshow(triu(M)); % UTM %[output:80b31cbc]
M2 = M;
M2(M2<5)=250;
figure(6), imshow(M2); % 밝기 5이하인 부분을 250으로 만들기 %[output:746ab3a8]
figure(7), imshow(circshift(M, [0 160])); % 우측으로 160 밀기 %[output:5c610593]
figure(8), imshow(flipud(M)); %상하반전 %[output:9d263b2e]

